<?php
namespace App\Http\Controllers\Admin;use App\Http\Controllers\Controller;use App\Models\Slider;use Illuminate\Http\{RedirectResponse,Request};use Illuminate\View\View;
class SliderController extends Controller{use HandlesAdminUploads;public function index():View{return view('admin.crud.index',['title'=>'مدیریت اسلایدرها','items'=>Slider::orderBy('sort_order')->paginate(15),'route'=>'sliders']);}public function create():View{return view('admin.sliders.form',['slider'=>new Slider(['is_active'=>true])]);}public function store(Request $r):RedirectResponse{$d=$this->data($r);$d['image']=$this->upload($r,'image','sliders');$d['mobile_image']=$this->upload($r,'mobile_image','sliders');Slider::create($d);return redirect()->route('admin.sliders.index')->with('success','ذخیره شد');}public function edit(Slider $slider):View{return view('admin.sliders.form',compact('slider'));}public function update(Request $r,Slider $slider):RedirectResponse{$d=$this->data($r);$d['image']=$this->upload($r,'image','sliders',$slider->image);$d['mobile_image']=$this->upload($r,'mobile_image','sliders',$slider->mobile_image);$slider->update($d);return redirect()->route('admin.sliders.index')->with('success','به‌روزرسانی شد');}public function destroy(Slider $slider):RedirectResponse{$slider->delete();return back();}private function data(Request $r):array{return $r->validate(['title'=>'required','subtitle'=>'nullable','image'=>'nullable|image|max:3072','mobile_image'=>'nullable|image|max:3072','button_text'=>'nullable','button_link'=>'nullable','display_mode'=>'nullable','sort_order'=>'nullable|integer'])+['is_active'=>$r->boolean('is_active'),'show_mobile'=>$r->boolean('show_mobile',true),'show_desktop'=>$r->boolean('show_desktop',true)];}}
